class CovenantSection {
  final String title;
  final String content;

  CovenantSection({required this.title, required this.content});
}

final List<CovenantSection> covenantSections = [
  CovenantSection(
    title: 'المقدمة',
    content: '''انطلاقاً من الشعور بالمسؤولية واستجابة لمقتضيات المصلحة العامة لعشائر بني حمدان والمناشدات المستمرة من قبل الأعمام، فقد اجتمعت نخبة خيرة من الرجال المخلصين والصادقين في مضيف الشيخ عبيد السهر بتاريخ 2026/2/6.
بعد مداولات مستمرة وحثيثة، تم فيها الاستماع إلى جميع الآراء وأثمرت عن صياغة هذا الميثاق المبارك الذي طال انتظاره منذ عشرات السنين، ليكون بمثابة قانون عشائري يوفر الحماية لكل من ينتمي إليه، ولكي يكون سنداً وعوناً بين الأعمام في أوقات الشدائد والملمات، وخاصة ونحن نعيش في مجتمع كثر فيه المشاكل والحوادث التي يترتب عليها التزامات مادية تحت مسمى (الدية)، لا يمكن للفرد الواحد الوفاء بها لوحده دون الانتماء إلى هذا الميثاق.''',
  ),
  CovenantSection(
